import React, { useState, useRef, useEffect } from 'react';
import { Play, Pause, RotateCcw, FileText } from 'lucide-react';
import { PRINCIPAL_MESSAGE } from '../constants';

export const AudioPlayer: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [showTranscript, setShowTranscript] = useState(false);
  const [progress, setProgress] = useState(0);

  // Simulation of audio playback since we don't have a real file
  useEffect(() => {
    let interval: any;
    if (isPlaying) {
      interval = setInterval(() => {
        setProgress((prev) => {
          if (prev >= 100) {
            setIsPlaying(false);
            return 100;
          }
          return prev + 1;
        });
      }, 300); // approx 30 seconds for full bar
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handlePlayToggle = () => {
    setIsPlaying(!isPlaying);
  };

  const handleReset = () => {
    setIsPlaying(false);
    setProgress(0);
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-lg border border-gray-100 max-w-xl mx-auto">
      <div className="text-center mb-8">
        <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-blue-100">
          <div className={`w-3 h-3 bg-blue-500 rounded-full ${isPlaying ? 'animate-ping' : ''}`} />
        </div>
        <h3 className="text-xl font-bold text-gray-800">校長先生の話（録音）</h3>
        <p className="text-gray-500 text-sm mt-1">再生時間: 約30秒</p>
      </div>

      <div className="mb-8">
        <div className="h-2 bg-gray-100 rounded-full overflow-hidden mb-2">
          <div 
            className="h-full bg-blue-500 transition-all duration-300 ease-linear"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="flex justify-between text-xs text-gray-400 font-mono">
          <span>0:{(Math.floor(progress * 0.3)).toString().padStart(2, '0')}</span>
          <span>0:30</span>
        </div>
      </div>

      <div className="flex items-center justify-center space-x-6 mb-8">
        <button 
          onClick={handleReset}
          className="p-3 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
          aria-label="リセット"
        >
          <RotateCcw className="w-6 h-6" />
        </button>
        <button 
          onClick={handlePlayToggle}
          className="w-16 h-16 bg-blue-600 text-white rounded-full flex items-center justify-center hover:bg-blue-700 shadow-lg hover:shadow-xl transform hover:scale-105 transition-all"
          aria-label={isPlaying ? "一時停止" : "再生"}
        >
          {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
        </button>
        <button 
          onClick={() => setShowTranscript(!showTranscript)}
          className={`p-3 rounded-full transition-colors ${showTranscript ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100'}`}
          aria-label="文字起こしを表示"
        >
          <FileText className="w-6 h-6" />
        </button>
      </div>

      {showTranscript && (
        <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 animate-in fade-in slide-in-from-top-2 duration-300">
          <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">文字起こし</h4>
          <p className="text-gray-700 leading-relaxed text-lg">
            「{PRINCIPAL_MESSAGE}」
          </p>
        </div>
      )}
    </div>
  );
};

