import React, { useState, useRef } from 'react';
import { Play, Pause, RotateCcw, FileText, Loader2, Calendar } from 'lucide-react';
import { GoogleGenAI, Modality } from "@google/genai";
import { PRINCIPAL_MESSAGE, INFO_SOURCES } from '../constants';

// Audio decoding helpers
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const AudioPlayer: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showTranscript, setShowTranscript] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null);

  const generateAndPlay = async () => {
    if (isPlaying) {
      sourceNodeRef.current?.stop();
      setIsPlaying(false);
      return;
    }

    if (audioBufferRef.current) {
      playBuffer(audioBufferRef.current);
      return;
    }

    try {
      setIsGenerating(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `落ち着いた年配の男性教師の声で話してください: ${PRINCIPAL_MESSAGE}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio data not found");

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioData = decodeBase64(base64Audio);
      const buffer = await decodeAudioData(audioData, audioContextRef.current, 24000, 1);
      audioBufferRef.current = buffer;

      playBuffer(buffer);
    } catch (error) {
      console.error("TTS Error:", error);
      alert("音声の生成に失敗しました。しばらく待ってからやり直してください。");
    } finally {
      setIsGenerating(false);
    }
  };

  const playBuffer = (buffer: AudioBuffer) => {
    if (!audioContextRef.current) return;

    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current.destination);
    source.onended = () => setIsPlaying(false);

    sourceNodeRef.current = source;
    source.start(0);
    setIsPlaying(true);
  };

  const handleReset = () => {
    sourceNodeRef.current?.stop();
    setIsPlaying(false);
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-lg border border-gray-100 max-w-xl mx-auto">
      <div className="text-center mb-8">
        <div className="inline-flex items-center px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-sm font-bold mb-4">
          <Calendar className="w-4 h-4 mr-2" />
          {INFO_SOURCES.A.date}
        </div>
        <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-blue-100">
          <div className={`w-3 h-3 bg-blue-500 rounded-full ${isPlaying ? 'animate-ping' : ''}`} />
        </div>
        <h3 className="text-xl font-bold text-gray-800">{INFO_SOURCES.A.title}</h3>
        <p className="text-gray-500 text-sm mt-1">再生ボタンを押すと先生の声が流れます</p>
      </div>

      <div className="flex items-center justify-center space-x-6 mb-8">
        <button 
          onClick={handleReset}
          className="p-3 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
          aria-label="リセット"
          disabled={isGenerating}
        >
          <RotateCcw className="w-6 h-6" />
        </button>
        <button 
          onClick={generateAndPlay}
          disabled={isGenerating}
          className={`w-16 h-16 rounded-full flex items-center justify-center shadow-lg transform hover:scale-105 transition-all ${
            isGenerating ? 'bg-gray-100 text-gray-400' : 'bg-blue-600 text-white hover:bg-blue-700'
          }`}
        >
          {isGenerating ? (
            <Loader2 className="w-8 h-8 animate-spin" />
          ) : isPlaying ? (
            <Pause className="w-8 h-8 fill-current" />
          ) : (
            <Play className="w-8 h-8 fill-current ml-1" />
          )}
        </button>
        <button 
          onClick={() => setShowTranscript(!showTranscript)}
          className={`p-3 rounded-full transition-colors ${showTranscript ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100'}`}
          aria-label="文字起こしを表示"
        >
          <FileText className="w-6 h-6" />
        </button>
      </div>

      {showTranscript && (
        <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 animate-in fade-in slide-in-from-top-2 duration-300">
          <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">文字起こし</h4>
          <p className="text-gray-700 leading-relaxed text-lg">
            「{PRINCIPAL_MESSAGE}」
          </p>
        </div>
      )}
    </div>
  );
};

